55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: 25,
63	  moonstone: 25,
64	};
65	
66	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
67	
68	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
69	const BLOCK_SIZE = 3;
70	const BLOCK_PREMIUM = 60;
71	
72	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
73	
74	const sumBasePremiums = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
76	
77	const componentsPremium = (components: Item[]): number => {
78	  const byType = new Map<string, Item[]>();
79	  for (const c of components) {
80	    const list = byType.get(c.type) ?? [];
81	    list.push(c);
82	    byType.set(c.type, list);
83	  }
84	  let total = 0;
85	  for (const group of byType.values()) {
86	    total += group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBasePremiums(group);
87	  }
88	  return total;
89	};
90	
91	const sumItemBasePremiums = (items: Item[]): number =>
92	  componentsPremium(items.filter(isComponent)) +
93	  sumBasePremiums(items.filter((item) => !isComponent(item)));
94	
95	const quotePremium = (items: Item[]): number =>
96	  sumItemBasePremiums(items) + PROCESSING_FEE;
