98	export const runScenario = (scenario: Scenario): ScenarioResult => {
99	  const results = scenario.steps.map((step): StepResult => {
100	    if (step.op === "quote") {
101	      return { premium: quotePremium(step.items) };
102	    }
103	    return { payout: 0, remainingCap: 0 };
104	  });
105	  return { results };
106	};
